-- ERASM Database Schema - MySQL 8.4.9
CREATE TABLE IF NOT EXISTS roles (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(50) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS users (id BIGINT PRIMARY KEY AUTO_INCREMENT, email VARCHAR(150) NOT NULL UNIQUE, password VARCHAR(255) NOT NULL, role_id BIGINT NOT NULL, is_active BOOLEAN DEFAULT TRUE, failed_login_attempts INT DEFAULT 0, account_locked BOOLEAN DEFAULT FALSE, locked_at TIMESTAMP NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, created_by VARCHAR(150), modified_by VARCHAR(150), FOREIGN KEY (role_id) REFERENCES roles(id));
CREATE TABLE IF NOT EXISTS employees (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL UNIQUE, first_name VARCHAR(100) NOT NULL, last_name VARCHAR(100) NOT NULL, phone VARCHAR(20), department VARCHAR(100), designation VARCHAR(100), date_of_joining DATE, employment_type VARCHAR(50), bench_status BOOLEAN DEFAULT TRUE, total_experience_years DOUBLE DEFAULT 0.0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, created_by VARCHAR(150), modified_by VARCHAR(150), FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS skills (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(100) NOT NULL UNIQUE, category VARCHAR(100), description TEXT, is_active BOOLEAN DEFAULT TRUE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS employee_skills (id BIGINT PRIMARY KEY AUTO_INCREMENT, employee_id BIGINT NOT NULL, skill_id BIGINT NOT NULL, level VARCHAR(20) NOT NULL, years_of_experience DOUBLE DEFAULT 0.0, last_used_date DATE, UNIQUE KEY uq_emp_skill (employee_id, skill_id), FOREIGN KEY (employee_id) REFERENCES employees(id) ON DELETE CASCADE, FOREIGN KEY (skill_id) REFERENCES skills(id));
CREATE TABLE IF NOT EXISTS certifications (id BIGINT PRIMARY KEY AUTO_INCREMENT, employee_id BIGINT NOT NULL, name VARCHAR(200) NOT NULL, issuing_organization VARCHAR(200), issue_date DATE, expiry_date DATE, credential_id VARCHAR(200), credential_url VARCHAR(500), FOREIGN KEY (employee_id) REFERENCES employees(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS projects (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(200) NOT NULL, client_name VARCHAR(200), description TEXT, start_date DATE NOT NULL, end_date DATE, status VARCHAR(50) DEFAULT 'ACTIVE', technology_stack TEXT, budget DECIMAL(15,2), created_by BIGINT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, modified_by VARCHAR(150), FOREIGN KEY (created_by) REFERENCES users(id));
CREATE TABLE IF NOT EXISTS resource_requests (id BIGINT PRIMARY KEY AUTO_INCREMENT, project_id BIGINT NOT NULL, requested_by BIGINT NOT NULL, skill_id BIGINT NOT NULL, skill_level VARCHAR(20), required_count INT NOT NULL DEFAULT 1, status VARCHAR(50) DEFAULT 'DRAFT', remarks TEXT, requested_start_date DATE, requested_end_date DATE, reviewed_by BIGINT, reviewed_at TIMESTAMP NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (project_id) REFERENCES projects(id), FOREIGN KEY (requested_by) REFERENCES users(id), FOREIGN KEY (skill_id) REFERENCES skills(id), FOREIGN KEY (reviewed_by) REFERENCES users(id));
CREATE TABLE IF NOT EXISTS allocations (id BIGINT PRIMARY KEY AUTO_INCREMENT, employee_id BIGINT NOT NULL, project_id BIGINT NOT NULL, resource_request_id BIGINT, allocation_percentage INT NOT NULL, start_date DATE NOT NULL, end_date DATE, status VARCHAR(50) DEFAULT 'ACTIVE', allocated_by BIGINT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, modified_by VARCHAR(150), FOREIGN KEY (employee_id) REFERENCES employees(id), FOREIGN KEY (project_id) REFERENCES projects(id), FOREIGN KEY (resource_request_id) REFERENCES resource_requests(id), FOREIGN KEY (allocated_by) REFERENCES users(id));
CREATE TABLE IF NOT EXISTS audit_logs (id BIGINT PRIMARY KEY AUTO_INCREMENT, entity_type VARCHAR(100) NOT NULL, entity_id BIGINT, action VARCHAR(50) NOT NULL, performed_by VARCHAR(150), description TEXT, ip_address VARCHAR(50), timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS refresh_tokens (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, token VARCHAR(500) NOT NULL UNIQUE, expiry_date TIMESTAMP NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS blacklisted_tokens (id BIGINT PRIMARY KEY AUTO_INCREMENT, token VARCHAR(500) NOT NULL UNIQUE, token_type VARCHAR(20) NOT NULL DEFAULT 'ACCESS', blacklisted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, expires_at TIMESTAMP NOT NULL);

